// SAFE protocol: the Escrow holds the Buyer's funds FIRST, which breaks the
// circular "pay-after-deliver / ship-after-pay" wait that the intent describes.
// (The unchecked skills version of the same intent deadlocks; Scribble rejects
// any protocol that keeps the cycle, forcing this escrow-first ordering.)
global protocol TradeDeadlock(role Buyer, role Seller, role Escrow, role Carrier) {
    FundEscrow(Double) from Buyer to Escrow;
    FundsSecured(String) from Escrow to Seller;
    ShipGoods(String) from Seller to Carrier;
    DeliverGoods(String) from Carrier to Buyer;
    ConfirmReceipt(String) from Buyer to Escrow;
    ReleasePayment(Double) from Escrow to Seller;
    SettlementComplete(String) from Escrow to Buyer;
}

